**PIXEL SPRITE RENDERER** — Creates pixel sprites from a grid pattern (use for ALL game entities):
```js
function renderSprite(grid, colors, scale) {
  scale = scale || 4;
  const h = grid.length, w = grid[0].length;
  let svg = '<svg viewBox="0 0 ' + (w*scale) + ' ' + (h*scale) + '" xmlns="http://www.w3.org/2000/svg">';
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const c = colors[grid[y][x]];
      if (c) svg += '<rect x="' + (x*scale) + '" y="' + (y*scale) + '" width="' + scale + '" height="' + scale + '" fill="' + c + '"/>';
    }
  }
  return svg + '</svg>';
}
```

