// Generate shield shape (arch with flat top)
function createShield(container) {
  // 22x16 grid, arch shape
  const shape = [];
  for (let y = 0; y < 16; y++) {
    for (let x = 0; x < 22; x++) {
      const inArch = y > 10 && x > 6 && x < 15; // hollow center bottom
      const inBody = (y < 3 && x > 2 && x < 19) ||
                     (y >= 3 && y <= 10) ||
                     (y > 10 && !inArch);
      if (inBody) {
        const block = document.createElement('div');
        block.className = 'shield-block';
        block.dataset.x = x; block.dataset.y = y;
        container.appendChild(block);
      } else {
        const empty = document.createElement('div');
        container.appendChild(empty);
      }
    }
  }
}
// Damage shield: remove blocks near hit point
function damageShield(container, hitX, hitY, radius) {
  container.querySelectorAll('.shield-block:not(.destroyed)').forEach(b => {
    const bx = parseInt(b.dataset.x), by = parseInt(b.dataset.y);
    if (Math.abs(bx - hitX) + Math.abs(by - hitY) <= radius) {
      b.classList.add('destroyed');
    }
  });
}
